${convoText}
${nextQuestionHint}

React briefly to the last answer (1 sentence), then ask your next question.
Actions: "follow_up" (vague answer), "challenge" (test deeper), "transition" (solid, move on), "wrap_up" (8+ exchanges done).

Return JSON: {"reaction":"...","action":"...","question":"...","score_hint":1-10,"notes":"..."}`;

  const result = await chat(prompt, {
    system: `Expert ${targetRole} interviewer. Brief, natural reactions. Push for specifics on vague answers. Always valid JSON.`,
    maxTokens: 1024,
    subscriptionId: options.subscriptionId
  });

  try {
    return JSON.parse(result);
  } catch (e) {
    const match = result.match(/\{[\s\S]*\}/);
    if (match) return JSON.parse(match[0]);
    throw new Error('Failed to generate interview turn');
  }
}

// Generate session-end feedback for a mock interview
async function generateSessionFeedback(conversation, targetRole, options = {}) {
  const convoText = conversation.map(turn => {
    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
    return `CANDIDATE: ${turn.text}`;
  }).join('\n\n');

  const prompt = `You just completed a mock interview for a "${targetRole}" position. Review the full conversation and provide comprehensive feedback.

FULL INTERVIEW TRANSCRIPT:
${convoText}

Provide a thorough, detailed assessment covering EVERY dimension:

Return a JSON object:
{
  "overall_score": 1-10,
  "interview_readiness": "ready|almost_ready|needs_work",
  "summary": "3-4 sentence overall assessment that is specific and references their actual answers",
  "strengths": ["Strength 1 with specific example from their answers", "Strength 2", "Strength 3"],
  "improvements": ["Improvement 1 with specific example", "Improvement 2", "Improvement 3"],
  "question_scores": [
    { "question_summary": "Brief question topic", "score": 1-10, "feedback": "1-2 sentence feedback referencing their actual answer" }
  ],
  "star_method_usage": { "score": 1-10, "feedback": "How well they used Situation-Task-Action-Result structure" },
  "communication_quality": { "score": 1-10, "feedback": "Clarity, conciseness, confidence, use of filler words" },
  "technical_depth": { "score": 1-10, "feedback": "Depth of technical knowledge, specificity of examples" },
  "confidence_score": { "score": 1-10, "feedback": "How confident and assured they sounded — hedging, qualifiers, decisiveness" },
  "top_tip": "The single most impactful thing they should work on before their real interview"
}

Be SPECIFIC — reference actual things they said. Quote their words when possible. Don't be generic.
Score honestly — a 5 is average, not bad. Only give 8+ for genuinely strong performance.

Only return the JSON object.`;

  const result = await chat(prompt, {
    system: 'You are a career coach providing post-interview feedback. Be honest, specific, and constructive. Reference exact things from the interview. Always return valid JSON.',
    maxTokens: 4096,
    subscriptionId: options.subscriptionId
  });

  try {
    return JSON.parse(result);
  } catch (e) {
    const match = result.match(/\{[\s\S]*\}/);
    if (match) return JSON.parse(match[0]);
    return { overall_score: 5, summary: 'Interview completed. Detailed feedback unavailable.', interview_readiness: 'almost_ready' };
  }
}

// Text-to-Speech via OpenAI TTS API
// Returns a Buffer of audio data (mp3 format)
async function textToSpeech(text, options = {}) {
  try {
    const voice = options.voice || 'nova'; // nova = warm professional female voice
    const speed = options.speed || 1.0;

    // Truncate text to ~4000 chars (TTS API limit is 4096)
    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
    console.log(`[tts] Generating speech: ${truncatedText.length} chars, voice: ${voice}`);

    const baseUrl = process.env.OPENAI_BASE_URL || 'https://api.openai.com/v1';
    const apiKey = process.env.OPENAI_API_KEY;
    const headers = {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
    };
    if (options.subscriptionId) headers['X-Subscription-ID'] = options.subscriptionId;

    const res = await fetch(`${baseUrl}/audio/speech`, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        model: 'tts-1',
        input: truncatedText,
        voice: voice,
        response_format: 'mp3',
        speed: speed,
        task: 'tts-interview',
      })
    });

    if (!res.ok) {
      const errText = await res.text();
      console.error('[tts] API error:', res.status, errText);
      return null;
    }

    // Return the raw audio buffer
    const arrayBuffer = await res.arrayBuffer();
    const buf = Buffer.from(arrayBuffer);
    console.log(`[tts] Generated ${buf.length} bytes of MP3 audio`);
    return buf;
  } catch (err) {
    console.error('[tts] Error:', err.message || err);
    return null;
  }
}

